ALTER COLUMN description TYPE TEXT;
INSERT INTO public.tour_detail (created_at, updated_at, day_number, day_title, dep, description, image, tour_id) VALUES

-- Tour 1: Hạ Long (3 ngày)
(NOW(), NOW(), 'Ngày 1', 'Hà Nội – Hạ Long – Lên Tàu', 'Hà Nội', 'Khởi hành 7h tại Hà Nội, xe limousine đưa đón tận nhà. Đến cảng Tuần Châu lúc 10h, làm thủ tục lên du thuyền 5 sao. Ăn trưa trên tàu với hải sản tươi. Buổi chiều tham quan Hang Sửng Sốt kỳ vĩ. Chiều tối: cocktail party trên boong, ngắm hoàng hôn Vịnh Hạ Long. Tối: BBQ hải sản ngoài trời, giải trí ca nhạc.', 'https://images.unsplash.com/photo-1563299796-17596ed6b017?w=600', 1),
(NOW(), NOW(), 'Ngày 2', 'Chèo Kayak & Đảo Titop', 'Vịnh Hạ Long', 'Buổi sáng: Thức dậy đón bình minh trên biển, tập Tai Chi trên boong. Ăn sáng kiểu buffet. Chèo kayak qua làng chài Vung Viêng. Buổi chiều: Tắm biển và leo 400 bậc đá lên đỉnh đảo Titop ngắm toàn cảnh Vịnh. Tối: tiệc hải sản đặc biệt trên tàu.', 'https://images.unsplash.com/photo-1570979236393-59561a95a5b7?w=600', 1),
(NOW(), NOW(), 'Ngày 3', 'Trở Về Hà Nội', 'Vịnh Hạ Long', 'Sáng sớm: điểm tâm, tổng vệ sinh cabin. Tham quan làng chài trên bè nổi. 11h: rời tàu, xe đưa về Hà Nội. Ghé siêu thị Quảng Ninh mua đặc sản chả mực, sá sùng. Về Hà Nội lúc 15h.', 'https://images.unsplash.com/photo-1509030450996-dd1a26dda07a?w=600', 1),

-- Tour 2: Sapa (4 ngày)
(NOW(), NOW(), 'Ngày 1', 'Hà Nội – Sapa Đêm Tàu', 'Hà Nội', 'Tập trung ga Hà Nội lúc 21h30. Tàu SP3 khởi hành 22h, giường nằm điều hòa. Thưởng thức lẩu trên tàu, giao lưu cùng hướng dẫn viên bản địa.', 'https://images.unsplash.com/photo-1571368618038-cf6afe56e9cf?w=600', 2),
(NOW(), NOW(), 'Ngày 2', 'Trekking Bản Cát Cát – Bản Lao Chải', 'Sapa', 'Đến Sapa sáng sớm, nhận phòng KS, ăn sáng. Trekking qua bản Cát Cát của người H''Mông Đen, thăm thác nước, thưởng thức rượu táo mèo. Chiều: tham quan chợ Sapa, mua thổ cẩm.', 'https://images.unsplash.com/photo-1540331547168-8b63109225b7?w=600', 2),
(NOW(), NOW(), 'Ngày 3', 'Chinh Phục Fansipan', 'Sapa', 'Cáp treo Sun World Fansipan 6h30 sáng, lên đỉnh 3.143m – nóc nhà Đông Dương. Chụp hình bia đỉnh, tham quan khu tâm linh đỉnh núi. Chiều: về Sapa, tắm thuốc của người Dao Đỏ.', 'https://images.unsplash.com/photo-1586348943529-beaae6c28db9?w=600', 2),
(NOW(), NOW(), 'Ngày 4', 'Sapa – Hà Nội', 'Sapa', 'Sáng: thăm ruộng bậc thang Mường Hoa mùa vàng. 10h: lên xe về Hà Nội, ghé thị trấn Bắc Hà mua sắm. Về Hà Nội lúc 18h, giải tán đoàn.', 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=600', 2),

-- Tour 4: Đà Nẵng (4 ngày)
(NOW(), NOW(), 'Ngày 1', 'Bay Đến Đà Nẵng – Bà Nà Hills', 'TP. Hồ Chí Minh', 'Bay sáng sớm đến Đà Nẵng. Nhận phòng KS 4 sao view biển. Buổi chiều: tham quan Bà Nà Hills (cáp treo dài 5.772m), chụp hình tại Cầu Vàng, dạo Fantasy Park. Tối: ăn tối tại nhà hàng hải sản Bạch Đằng, thưởng thức mì Quảng đặc sản.', 'https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?w=600', 4),
(NOW(), NOW(), 'Ngày 2', 'Hội An – Phố Cổ Đèn Lồng', 'Đà Nẵng', 'Xe đưa vào Hội An (30km). Tham quan phố cổ di sản UNESCO: Chùa Cầu Nhật Bản, nhà cổ Tấn Ký, Hội quán Phúc Kiến. Buổi chiều: thả đèn hoa đăng trên sông Hoài lung linh. Tối: ăn cao lầu, bánh mì Phượng nổi tiếng thế giới.', 'https://images.unsplash.com/photo-1526781100024-7e51f3e3d0a4?w=600', 4),
(NOW(), NOW(), 'Ngày 3', 'Ngũ Hành Sơn – Biển Mỹ Khê', 'Đà Nẵng', 'Sáng: leo Ngũ Hành Sơn (núi Thủy Sơn), thăm động Huyền Không linh thiêng. Buổi chiều: tắm biển Mỹ Khê – 1 trong 6 bãi biển quyến rũ nhất hành tinh theo Forbes. Tối: ăn bún cá Đà Nẵng, đi bộ cầu Rồng ngắm phun lửa.', 'https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=600', 4),
(NOW(), NOW(), 'Ngày 4', 'Về TP.HCM', 'Đà Nẵng', 'Sáng tự do tắm biển, mua quà. 11h check-out. Ăn trưa bánh tráng cuốn thịt heo đặc sản. Ra sân bay, bay về TP.HCM lúc 15h. Về đến TP.HCM lúc 16h30.', 'https://images.unsplash.com/photo-1559054663-e8d23213f55c?w=600', 4),

-- Tour 6: Phú Quốc (4 ngày)
(NOW(), NOW(), 'Ngày 1', 'Bay Đến Phú Quốc – Bãi Sao', 'TP. Hồ Chí Minh', 'Bay sáng đến Phú Quốc. Xe đưa về resort Sol Beach House 4 sao sát biển. Buổi chiều: tắm biển Bãi Sao – bãi biển đẹp nhất Việt Nam với cát trắng mịn và nước xanh trong vắt. Tối: chợ đêm Dinh Cậu sôi động, thưởng thức hải sản tươi sống.', 'https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=600', 6),
(NOW(), NOW(), 'Ngày 2', 'Lặn Biển Hòn Thơm 4 Đảo', 'Phú Quốc', 'Thuyền đưa tham quan 4 đảo: Hòn Thơm (lặn snorkeling ngắm san hô), Hòn Gầm Ghì, Hòn Vang. Ăn trưa trên tàu với cá tươi nướng. Chiều về tham quan Vinpearl Safari (safari lớn nhất VN).', 'https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=600', 6),
(NOW(), NOW(), 'Ngày 3', 'Hàm Ninh & Sunset Sanato', 'Phú Quốc', 'Sáng: xe máy khám phá bắc đảo, thăm làng chài Hàm Ninh, ăn ghẹ hấp sả tươi ngon. Chiều: cáp treo Hòn Thơm vượt biển (dài nhất thế giới 7.899m). Tối: xem hoàng hôn Mũi Ông Đội, cocktail sunset tại bar biển.', 'https://images.unsplash.com/photo-1596394516093-501ba68a0ba6?w=600', 6),
(NOW(), NOW(), 'Ngày 4', 'Về TP.HCM', 'Phú Quốc', 'Sáng tự do tắm biển lần cuối. Mua đặc sản: nước mắm Phú Quốc, tiêu đỏ, rượu sim. Ăn trưa cơm Ghẹ. Bay về TP.HCM lúc 15h, về đến nơi 16h30.', 'https://images.unsplash.com/photo-1504893524553-b855bce32c67?w=600', 6),

-- Tour 13: Nhật Bản (7 ngày)
(NOW(), NOW(), 'Ngày 1', 'Bay Đến Tokyo – Narita', 'TP. Hồ Chí Minh', 'Bay Vietnam Airlines VN300 lúc 0h. Đến Tokyo Narita sáng. Xe bus về trung tâm Tokyo, check-in KS Shinjuku. Buổi chiều: dạo Shinjuku, ngắm Kabukicho, mua sắm Takashimaya. Tối: ăn ramen Ichiran, dạo Omoide Yokocho.', 'https://images.unsplash.com/photo-1540959733332-eab4deabeeaf?w=600', 13),
(NOW(), NOW(), 'Ngày 2', 'Tokyo – Asakusa – Akihabara', 'Tokyo', 'Sáng: Asakusa (Senso-ji temple – đền cổ nhất Tokyo), Nakamise Shopping Street. Buổi trưa: Akihabara (thiên đường anime và điện tử). Chiều: Harajuku (Takeshita Street – thời trang đường phố), Omotesando. Tối: ngắm cảnh Tokyo từ Skytree 634m.', 'https://images.unsplash.com/photo-1540959733332-eab4deabeeaf?w=600', 13),
(NOW(), NOW(), 'Ngày 3', 'Núi Phú Sĩ – Hakone', 'Tokyo', 'Xe đưa đến núi Phú Sĩ (Fuji-san), tham quan hồ Kawaguchi, Trạm 5 Phú Sĩ (mùa xuân chụp anh đào trước núi). Hakone: tắm onsen, ngắm Phú Sĩ qua hồ Ashi, đi thuyền cướp biển.', 'https://images.unsplash.com/photo-1490806843957-31f4c9a91c65?w=600', 13),
(NOW(), NOW(), 'Ngày 4', 'Shinkansen – Osaka', 'Tokyo', 'Shinkansen Nozomi về Osaka (2h20). Chiều: Dotonbori – ăn takoyaki bạch tuộc, cua king, ramen. Mua sắm Shinsaibashi. Tối: ngắm đèn Dotonbori – Times Square của Osaka.', 'https://images.unsplash.com/photo-1590559899731-a382839e5549?w=600', 13),
(NOW(), NOW(), 'Ngày 5', 'Kyoto – Di Sản Ngàn Năm', 'Osaka', 'Tàu đến Kyoto. Tham quan Fushimi Inari (1.000 cổng torii đỏ huyền bí), Arashiyama Bamboo Grove (rừng tre xanh mướt), Kinkakuji (chùa Vàng). Buổi chiều: trà đạo Kyoto, mặc kimono dạo phố Gion.', 'https://images.unsplash.com/photo-1493976040374-85c8e12f0c0e?w=600', 13),
(NOW(), NOW(), 'Ngày 6', 'Nara – Hươu Thiêng', 'Kyoto', 'Xe lửa đến Nara (45 phút). Tham quan Todai-ji (đền Phật Lớn – Daibutsu khổng lồ 15m), cho hươu sika ăn bánh trong công viên Nara. Chiều về Osaka, mua sắm ngày cuối tại Umeda, Don Quijote.', 'https://images.unsplash.com/photo-1516280440614-37939bbacd81?w=600', 13),
(NOW(), NOW(), 'Ngày 7', 'Bay Về TP.HCM', 'Osaka', 'Sáng tự do mua sắm lần cuối. Xe ra sân bay Kansai. Bay VN306 lúc 14h, về TP.HCM lúc 18h30. Kết thúc hành trình Nhật Bản khó quên.', 'https://images.unsplash.com/photo-1512453979798-5ea266f8880c?w=600', 13),

-- Tour 14: Hàn Quốc (5 ngày)
(NOW(), NOW(), 'Ngày 1', 'Bay Đến Seoul – Incheon', 'Hà Nội', 'Bay 7C5101 lúc 6h đến Seoul Incheon. Xe đưa về Myeongdong check-in. Chiều: Gyeongbokgung Palace (cung điện Joseon), Bukchon Hanok Village (làng hanok cổ kính). Tối: Myeongdong Shopping – mua cosmetic K-beauty.', 'https://images.unsplash.com/photo-1517154421773-0529f29ea451?w=600', 14),
(NOW(), NOW(), 'Ngày 2', 'Đảo Nami – Petite France', 'Seoul', 'Xe đến hồ Cheongpyeong, thuyền ra đảo Nami (Namiseom) – thiên đường hàng cây bạch quả vàng mùa thu. Petite France – làng nhỏ nước Pháp giữa Hàn Quốc. Tối về Seoul, ăn BBQ bò Hanwoo nguyên bản.', 'https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=600', 14),
(NOW(), NOW(), 'Ngày 3', 'Busan – Thành Phố Biển', 'Seoul', 'KTX Busan (2h30). Tham quan Gamcheon Culture Village (làng bích họa sặc sỡ), chợ cá Jagalchi (hải sản tươi sống ăn tại chỗ), Haeundae Beach. Tối: ăn hải sản Busan, sashimi cá bơn tươi.', 'https://images.unsplash.com/photo-1579003593419-98f949b9398f?w=600', 14),
(NOW(), NOW(), 'Ngày 4', 'Seoul – Gangnam – Lotte World', 'Seoul', 'KTX về Seoul. Gangnam (tham quan đại lộ K-pop, cafe chill). Chiều: Lotte World (công viên giải trí lớn nhất trong nhà thế giới). Tối: Hongdae bar street, clubbing K-pop.', 'https://images.unsplash.com/photo-1517154421773-0529f29ea451?w=600', 14),
(NOW(), NOW(), 'Ngày 5', 'Bay Về Hà Nội', 'Seoul', 'Sáng: mua sắm Dongdaemun cuối cùng (LOTTE Mart – mua kimchi, rong biển, snack). Ra sân bay Incheon. Bay 7C5102 lúc 15h về Hà Nội lúc 17h30. Kết thúc chuyến đi Hàn Quốc tuyệt vời.', 'https://images.unsplash.com/photo-1540959733332-eab4deabeeaf?w=600', 14),

-- Tour 17: Châu Âu (10 ngày)
(NOW(), NOW(), 'Ngày 1', 'Bay Đến Paris', 'TP. Hồ Chí Minh', 'Bay VN51 lúc 23h. Đến Paris Charles de Gaulle sau 12h bay. Xe đưa về KS trung tâm Paris 4 sao. Buổi tối: dạo bộ bờ sông Seine, ngắm tháp Eiffel lung linh về đêm.', 'https://images.unsplash.com/photo-1467269204594-9661b134dd2b?w=600', 17),
(NOW(), NOW(), 'Ngày 2', 'Paris – Bảo Tàng Louvre', 'Paris', 'Sáng: Bảo tàng Louvre (tượng Venus de Milo, tranh Mona Lisa, Khải Hoàn Môn). Chiều: Champs-Élysées mua sắm, Moulin Rouge, Montmartre. Thuyền sông Seine ngắm Paris về đêm.', 'https://images.unsplash.com/photo-1502602898657-3e91760cbb34?w=600', 17),
(NOW(), NOW(), 'Ngày 3', 'Paris – Versailles', 'Paris', 'Cung điện Versailles (cách Paris 20km) – nơi ở của vua Louis XIV. Vườn hoa Versailles 800ha tuyệt đẹp. Chiều: Galeries Lafayette mua sắm xa xỉ.', 'https://images.unsplash.com/photo-1594961381736-f8b4e22a5ed0?w=600', 17),
(NOW(), NOW(), 'Ngày 4', 'Bay Đến Rome – Colosseum', 'Paris', 'Bay sáng đến Rome. Buổi chiều: Colosseum (đấu trường La Mã 2.000 năm), Khải Hoàn Môn Constantine, Forum Romanum. Tối: ăn pasta carbonara và pizza Napoli truyền thống.', 'https://images.unsplash.com/photo-1552832230-c0197dd311b5?w=600', 17),
(NOW(), NOW(), 'Ngày 5', 'Rome – Vatican', 'Rome', 'Vatican City: Quảng trường Thánh Peter, Vương cung thánh đường, Bảo tàng Vatican (trần nhà Sistine Chapel của Michelangelo). Đài phun nước Trevi ném xu cầu may. Tối: dạo Trastevere cổ kính.', 'https://images.unsplash.com/photo-1555992336-03a23c7b20ee?w=600', 17),
(NOW(), NOW(), 'Ngày 6', 'Florence – Thành Phố Nghệ Thuật', 'Rome', 'Tàu cao tốc đến Florence (1h30). Piazza del Duomo, Uffizi Gallery (tranh Botticelli), Ponte Vecchio lãng mạn, Piazzale Michelangelo ngắm toàn cảnh Florence. Tối: bít tết Florentine thơm ngon.', 'https://images.unsplash.com/photo-1513581166391-887a96ddeafd?w=600', 17),
(NOW(), NOW(), 'Ngày 7', 'Venice – Thành Phố Tình Yêu', 'Florence', 'Tàu đến Venice. Gondola trên kênh đào tình yêu, Quảng trường San Marco, Campanile Tháp chuông, Cầu Than thở. Mua sắm kính Murano và mặt nạ Venice. Tối: ăn tối bên kênh đào.', 'https://images.unsplash.com/photo-1534430480872-3498386e7856?w=600', 17),
(NOW(), NOW(), 'Ngày 8', 'Zurich – Hồ Lucerne', 'Venice', 'Xe đến Thuỵ Sĩ qua đèo Alps. Zurich: khu phố cổ, hồ Zurich. Lucerne: Hồ Lucerne soi bóng núi Pilatus tuyết trắng, Cầu gỗ Kapellbrücke 700 tuổi, đồng hồ Thuỵ Sĩ.', 'https://images.unsplash.com/photo-1431274172761-fcdab704bb6b?w=600', 17),
(NOW(), NOW(), 'Ngày 9', 'Interlaken – Jungfraujoch', 'Zurich', 'Tàu răng cưa lên Jungfraujoch (3.454m) – nóc nhà châu Âu, tuyết phủ quanh năm. Ngắm cảnh Alps hùng vĩ. Chiều: Interlaken dạo bộ, mua sô-cô-la và đồng hồ Rolex.', 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=600', 17),
(NOW(), NOW(), 'Ngày 10', 'Bay Về TP.HCM', 'Zurich', 'Sáng tự do mua sắm cuối. Bay VN56 từ Zurich lúc 14h qua Singapore, về TP.HCM sáng hôm sau. Kết thúc hành trình châu Âu 10 ngày trong mơ.', 'https://images.unsplash.com/photo-1476514525535-07fb3b4ae5f1?w=600', 17),

-- Tour 19: Dubai (5 ngày)
(NOW(), NOW(), 'Ngày 1', 'Bay Đến Dubai', 'Hà Nội', 'Bay EK392 lúc 22h. Đến Dubai International Airport sáng. Nhận phòng KS 5 sao tại JBR Beach. Buổi chiều: Dubai Mall (mall lớn nhất thế giới), Dubai Fountain show, Burj Khalifa tầng 124 ngắm hoàng hôn.', 'https://images.unsplash.com/photo-1512453979798-5ea266f8880c?w=600', 19),
(NOW(), NOW(), 'Ngày 2', 'Safari Sa Mạc', 'Dubai', 'Sáng: Dubai Frame (nhìn Old & New Dubai từ khung tranh khổng lồ 150m), Al Fahidi Historic District. Chiều: Desert Safari (4x4 lượn cồn cát, cưỡi lạc đà, chụp hình hoàng hôn sa mạc). Tối: BBQ dưới trời sao sa mạc, múa bụng, trình diễn Tanoura.', 'https://images.unsplash.com/photo-1518684079-3c830dcef090?w=600', 19),
(NOW(), NOW(), 'Ngày 3', 'Palm Jumeirah – Atlantis', 'Dubai', 'Xe đến Palm Jumeirah – đảo nhân tạo hình lá cọ. Atlantis The Palm Water Park. Monorail dạo đảo. Tối: xem show nhạc nước Dubai Mall (lớn nhất thế giới).', 'https://images.unsplash.com/photo-1512453979798-5ea266f8880c?w=600', 19),
(NOW(), NOW(), 'Ngày 4', 'Abu Dhabi – Sheikh Zayed', 'Dubai', 'Xe đến Abu Dhabi (150km). Grand Mosque Sheikh Zayed – nhà thờ Hồi giáo lớn nhất UAE dát đá quý. Ferrari World (công viên chủ đề Ferrari – xe F1 nhanh nhất thế giới). Tối về Dubai.', 'https://images.unsplash.com/photo-1512453979798-5ea266f8880c?w=600', 19),
(NOW(), NOW(), 'Ngày 5', 'Bay Về Hà Nội', 'Dubai', 'Sáng: Gold Souk mua vàng (giá rẻ hơn VN), Spice Souk mua gia vị. Ăn trưa buffet khách sạn. Bay EK393 lúc 15h, về Hà Nội sáng hôm sau.', 'https://images.unsplash.com/photo-1476514525535-07fb3b4ae5f1?w=600', 19),

-- Tour 15: Thái Lan (6 ngày)
(NOW(), NOW(), 'Ngày 1', 'Bay Đến Bangkok', 'TP. Hồ Chí Minh', 'Bay TG555 đến Suvarnabhumi. Nhận phòng KS Sukhumvit. Buổi chiều: Hoàng cung Thái Lan (Grand Palace), Wat Pho (Phật Nằm khổng lồ 46m). Tối: Khao San Road – khu phố Tây Bangkok sôi động.', 'https://images.unsplash.com/photo-1552465011-b4e21bf6e79a?w=600', 15),
(NOW(), NOW(), 'Ngày 2', 'Bangkok – Chợ Nổi & Wat Arun', 'Bangkok', 'Thuyền dọc kênh Chao Phraya, thăm Chợ Nổi Damnoen Saduak. Wat Arun (Chùa Rạng Đông) lúc hoàng hôn. Chiều: Jim Thompson House – bảo tàng lụa Thái. Tối: massage Thái 2 tiếng.', 'https://images.unsplash.com/photo-1508009603885-50cf7c8dd0d5?w=600', 15),
(NOW(), NOW(), 'Ngày 3', 'Bay Đến Pattaya', 'Bangkok', 'Xe đến Pattaya (2h). Show Alcazar – ca nhạc kịch hoành tráng nhất Thái Lan. Sanctuary of Truth – cung điện gỗ tâm linh độc đáo. Tối: Walking Street Pattaya. Ngủ tại resort Pattaya.', 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=600', 15),
(NOW(), NOW(), 'Ngày 4', 'Bay Đến Phuket', 'Pattaya', 'Bay nội địa đến Phuket. Nhận phòng resort Patong Beach. Chiều: đảo Phi Phi (thuyền speedboat) – bãi Maya Bay như phim The Beach. Tối: Bangla Road Phuket – đêm Phuket không ngủ.', 'https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=600', 15),
(NOW(), NOW(), 'Ngày 5', 'Phuket – Big Buddha', 'Phuket', 'Big Buddha Phuket (45m trắng sáng trên đỉnh đồi), Promthep Cape ngắm hoàng hôn đẹp nhất Phuket, Old Town Phuket kiến trúc Sino-Portuguese. Tối: Fantasea Show – đại nhạc kịch voi vàng hoành tráng.', 'https://images.unsplash.com/photo-1552465011-b4e21bf6e79a?w=600', 15),
(NOW(), NOW(), 'Ngày 6', 'Bay Về TP.HCM', 'Phuket', 'Sáng: Central Festival Phuket mua sắm, ăn Tom Yam Kung lần cuối. Bay về TP.HCM lúc 14h. Về đến nơi 15h30. Kết thúc hành trình Thái Lan 6 ngày.', 'https://images.unsplash.com/photo-1476514525535-07fb3b4ae5f1?w=600', 15);


