-- ============================================================
-- ### 8. order_details (40 records – 1 detail per order for simplicity)
-- ============================================================
select * from order_details;
-- ============================================================
-- order_details – FIX: dùng subquery tra tour_schedule_id
-- theo (tour_id, departure_date) thay vì hardcode
-- ============================================================
INSERT INTO public.order_details (
    order_id, tour_id, tour_schedule_id, tour_name,
    adult_price, adult_quantity,
    child_price, child_quantity,
    infant_price, infant_quantity,
    departure_date, return_date, subtotal
)
SELECT
    v.order_id, v.tour_id,
    (SELECT ts.id FROM public.tour_schedules ts
     WHERE ts.tour_id = v.tour_id AND ts.departure_date = v.dep_date
        LIMIT 1) AS tour_schedule_id,
    v.tour_name,
    v.adult_price, v.adult_qty,
    v.child_price, v.child_qty,
    v.infant_price, v.infant_qty,
    v.dep_date, v.ret_date, v.subtotal
FROM (VALUES
    -- (order_id, tour_id, tour_name, adult_price, adult_qty, child_price, child_qty, infant_price, infant_qty, dep_date, ret_date, subtotal)
    (1,  7,  'Nha Trang – Thiên Đường Biển Xanh 3N2Đ 2025',           4200000.00, 2, 2940000.00, 1, 0.00, 0, DATE '2025-05-16', DATE '2025-05-18', 11340000.00),
    (2,  17, 'Châu Âu – Pháp Ý Thuỵ Sĩ 10N9Đ Mùa Hè 2025',          59900000.00, 1,       0.00, 0, 0.00, 0, DATE '2025-06-05', DATE '2025-06-14', 59900000.00),
    (3,  7,  'Nha Trang – Thiên Đường Biển Xanh 3N2Đ 2025',           4200000.00, 1,       0.00, 0, 0.00, 0, DATE '2025-05-16', DATE '2025-05-18',  4200000.00),
    (4,  13, 'Nhật Bản – Tokyo Osaka Kyoto Nara 7N6Đ Mùa Anh Đào 2025',29900000.00,1,      0.00, 0, 0.00, 0, DATE '2025-09-12', DATE '2025-09-18', 29900000.00),
    (5,  6,  'Phú Quốc – Đảo Ngọc Thiên Đường 4N3Đ Hè 2025',         6990000.00, 1,       0.00, 0, 0.00, 0, DATE '2025-04-30', DATE '2025-05-03',  6990000.00),
