-- ============================================================
-- ### 10. reviews (40 records)
-- ============================================================
INSERT INTO public.reviews (created_at, updated_at, tour_id, user_id, order_id, rating, title, comment, images, replied_at) VALUES
                                                                                                                                ('2025-04-20 10:00:00', NOW(), 1, 7, 7, 5, 'Chuyến đi Hạ Long tuyệt vời nhất từ trước đến nay!', 'Du thuyền sang trọng, đồ ăn hải sản siêu tươi ngon. Hang Sửng Sốt đẹp như trong phim. Hướng dẫn viên Minh rất nhiệt tình và vui tính. Nhất định sẽ quay lại!', '["https://images.unsplash.com/photo-1563299796-17596ed6b017?w=400","https://images.unsplash.com/photo-1570979236393-59561a95a5b7?w=400"]', NULL),
                                                                                                                                ('2025-04-22 14:30:00', NOW(), 13, 4, 4, 5, 'Nhật Bản mùa anh đào – không có từ nào diễn tả được!', 'Hoa anh đào nở rộ đúng dịp đi, Kyoto đẹp như cổ tích. HDV anh Tuấn hiểu biết rất sâu về văn hoá Nhật, tour được tổ chức rất chu đáo từ A-Z. Thức ăn ngon, khách sạn sạch. 10/10!', '["https://images.unsplash.com/photo-1540959733332-eab4deabeeaf?w=400"]', '2025-04-23 08:00:00'),
                                                                                                                                ('2025-04-25 09:15:00', NOW(), 6, 8, 5, 5, 'Phú Quốc – thiên đường thật sự!', 'Bãi Sao đẹp hơn trong ảnh rất nhiều. Nước biển xanh trong như pha lê. Resort Sol Beach House phục vụ rất tốt. Lặn biển Hòn Thơm thấy san hô đẹp mê hồn. Sẽ giới thiệu cho bạn bè!', '["https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=400","https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=400"]', NULL),
                                                                                                                                ('2025-04-28 16:00:00', NOW(), 4, 11, 11, 5, 'Đà Nẵng – Hội An đẹp quá!', 'Cầu Vàng Bà Nà Hills chụp hình đẹp lắm. Hội An buổi tối đèn lồng lung linh cực kỳ lãng mạn. Bánh mì Phượng nổi tiếng đúng là ngon thật. Tour gia đình rất phù hợp!', '["https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?w=400"]', '2025-04-29 09:00:00'),
                                                                                                                                ('2025-05-02 11:00:00', NOW(), 17, 5, 2, 5, '10 ngày châu Âu – hành trình trong mơ!', 'Tháp Eiffel, Colosseum, Thuỵ Sĩ tuyết trắng – tất cả đều hơn mong đợi. Tour tổ chức rất chuyên nghiệp, không có thời gian chờ đợi lãng phí. Khách sạn đẹp, hướng dẫn viên anh Hải rất giỏi tiếng Pháp và Ý. Cảm ơn TravelAPI!', '["https://images.unsplash.com/photo-1467269204594-9661b134dd2b?w=400","https://images.unsplash.com/photo-1502602898657-3e91760cbb34?w=400"]', '2025-05-03 08:00:00'),
                                                                                                                                ('2025-05-05 14:30:00', NOW(), 14, 9, 6, 4, 'Hàn Quốc đẹp nhưng thời tiết hơi lạnh', 'Seoul rất đẹp và hiện đại. Đảo Nami lãng mạn như trong phim Bản Tình Ca Mùa Đông. BBQ Hàn ngon tuyệt. Chỉ tiếc thời tiết tháng 4 còn hơi lạnh, nên mang thêm áo ấm.', '["https://images.unsplash.com/photo-1517154421773-0529f29ea451?w=400"]', NULL),
                                                                                                                                ('2025-05-08 09:45:00', NOW(), 23, 10, 8, 5, 'Bali honeymoon tuyệt vời!', 'Villa hồ bơi riêng siêu lãng mạn. Ubud yên tĩnh và thơ mộng. Lớp nấu ăn Bali rất vui. Kecak Fire Dance tại Uluwatu cực kỳ ấn tượng. Spa Bali thư giãn tuyệt vời. Sẽ quay lại năm sau!', '["https://images.unsplash.com/photo-1537996194471-e657df975ab4?w=400","https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=400"]', '2025-05-09 08:30:00'),
                                                                                                                                ('2025-05-10 16:00:00', NOW(), 7, 6, 3, 4, 'Nha Trang đẹp, Vinpearl hơi đông', 'Biển Nha Trang trong xanh tuyệt đẹp. Lặn biển 4 đảo ngắm san hô đẹp. Tắm bùn I-Resort thú vị lắm. Chỉ tiếc Vinpearl Land hôm đó đông khách quá nên xếp hàng lâu. Nhìn chung vẫn 4 sao!', NULL, NULL),
                                                                                                                                ('2025-05-12 11:30:00', NOW(), 19, 7, 13, 5, 'Dubai – thành phố của những kỷ lục thế giới!', 'Burj Khalifa lên tầng 124 nhìn toàn thành phố choáng ngợp. Safari sa mạc cưỡi lạc đà cực kỳ vui. Nhà thờ Sheikh Zayed đẹp tráng lệ. Tour tổ chức xuất sắc, mọi thứ đều on-time. Cảm ơn!', '["https://images.unsplash.com/photo-1512453979798-5ea266f8880c?w=400"]', '2025-05-13 09:00:00'),
                                                                                                                                ('2025-05-15 13:00:00', NOW(), 21, 4, 10, 5, 'Angkor Wat – kỳ quan thế giới không thể bỏ lỡ!', 'Bình minh Angkor Wat mà không xem một lần thì tiếc cả đời. Ta Prohm cây rễ nuốt đền đẹp như phim. Tuk-tuk xuyên đêm Siem Reap thú vị. Hướng dẫn viên người Campuchia nói tiếng Việt rất giỏi!', '["https://images.unsplash.com/photo-1539367628448-4bc5c9d171c8?w=400"]', NULL),
                                                                                                                                ('2025-05-18 10:00:00', NOW(), 15, 12, 12, 4, 'Thái Lan 6 ngày – xứng đáng từng đồng', 'Bangkok, Pattaya, Phuket – 3 điểm đến hoàn toàn khác nhau trong 1 tour. Grand Palace đẹp nguy nga. Đảo Phi Phi Maya Bay đẹp như tranh vẽ. Massage Thái 2 tiếng mà chỉ 200 baht rất đáng. Sẽ đi lại!', NULL, NULL),
                                                                                                                                ('2025-05-20 15:30:00', NOW(), 9, 11, 17, 5, 'Côn Đảo hoang sơ và đầy ý nghĩa', 'Biển Đầm Trầu trong xanh nhất tôi từng thấy. Lặn biển nhìn thấy rùa biển bơi ngay trước mặt – khoảnh khắc không bao giờ quên. Đến thắp hương tưởng nhớ cô Võ Thị Sáu rất xúc động. Tour ý nghĩa!', '["https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=400"]', '2025-05-21 09:00:00'),
                                                                                                                                ('2025-05-22 14:00:00', NOW(), 2, 5, NULL, 5, 'Sapa mùa vàng – đẹp đến nghẹt thở!', 'Ruộng bậc thang Sapa tháng 9 lúa chín vàng rực – đẹp hơn bất kỳ tấm ảnh nào. Trekking qua bản Cát Cát gặp trẻ em H''Mông rất đáng yêu. Đỉnh Fansipan nhìn biển mây trắng bồng bềnh. Sẽ quay lại mùa đông!', '["https://images.unsplash.com/photo-1571368618038-cf6afe56e9cf?w=400"]', NULL),
                                                                                                                                ('2025-05-25 09:00:00', NOW(), 24, 12, 9, 5, 'Mỹ 12 ngày – chuyến đi đổi đời!', 'Tượng Nữ Thần Tự Do ngoài thực tế nhỏ hơn trong ảnh nhưng ý nghĩa vẫn rất lớn. Grand Canyon hùng vĩ đến mức không chụp ảnh được hết. Las Vegas về đêm rực rỡ như tranh. Tour rất chuyên nghiệp!', '["https://images.unsplash.com/photo-1501594907352-04cda38ebc29?w=400","https://images.unsplash.com/photo-1546436836-07a91091f160?w=400"]', '2025-05-26 08:00:00'),
                                                                                                                                ('2025-05-28 11:30:00', NOW(), 16, 10, 16, 4, 'Singapore sạch đẹp, KL sôi động', 'Gardens by the Bay về đêm lung linh tuyệt đẹp. Universal Studios Singapore rất vui. Petronas Tower to hơn nghĩ nhiều. Genting Highlands mát mẻ dễ chịu. Tổng thể tour rất ổn, chỉ hơi rush.', '["https://images.unsplash.com/photo-1525625293386-3f8f99389edd?w=400"]', NULL),
                                                                                                                                ('2025-06-01 14:00:00', NOW(), 22, 11, 26, 5, 'Jeju mùa hoa canola vàng – siêu đẹp!', 'Cánh đồng hoa canola vàng rực dưới nắng xuân Jeju đẹp như thiên đường. Seongsan Ilchulbong bình minh tuyệt đẹp. Hải sản Jeju tươi ngon. Tắm biển Hamdeok nước xanh trong. Rất đáng đi!', '["https://images.unsplash.com/photo-1578662996442-48f60103fc96?w=400"]', '2025-06-02 09:00:00'),
                                                                                                                                ('2025-06-05 10:00:00', NOW(), 20, 9, 22, 5, 'Australia – thiên nhiên hoang dã đỉnh của chóp!', 'Lặn Great Barrier Reef là trải nghiệm không thể quên trong đời. Ôm koala tại wildlife Sydney dễ thương quá. Great Ocean Road lái xe ngắm cảnh đẹp tuyệt vời. Tour Úc rất đáng đồng tiền dù giá cao!', '["https://images.unsplash.com/photo-1523482580672-f109ba8cb9be?w=400"]', NULL),
                                                                                                                                ('2025-06-08 15:00:00', NOW(), 12, 8, 23, 4, 'Quy Nhơn bãi biển đẹp nhất miền Trung!', 'Kỳ Co trong xanh đẹp hơn Phú Quốc mà ít người biết đến. Cua huỳnh đế siêu ngon, chưa ăn bao giờ. Tháp Chàm Bình Định 1000 năm rất ấn tượng. Chỉ tiếc khách sạn hơi xa trung tâm một chút.', NULL, NULL),
                                                                                                                                ('2025-06-10 11:00:00', NOW(), 8, 6, NULL, 5, 'Đà Lạt mùa Giáng Sinh – romantic nhất!', 'Đà Lạt tháng 12 trang trí Noel rực rỡ lung linh. Thung lũng tình yêu sương mù lãng mạn cực kỳ. Dâu tây tươi hái thẳng từ vườn ngọt và mọng nước. Cà phê và rượu vang Đà Lạt ngon đặc biệt!', '["https://images.unsplash.com/photo-1599640842225-85d111c60e6b?w=400"]', NULL),
                                                                                                                                ('2025-06-12 14:30:00', NOW(), 1, 9, 39, 4, 'Hạ Long đẹp nhưng cần cải thiện thức ăn sáng', 'Vịnh Hạ Long đúng là kỳ quan. Chèo kayak rất thú vị. Nhưng bữa sáng trên thuyền hơi đơn điệu so với giá. Sẽ đặt du thuyền hạng cao hơn lần sau. Nhìn chung trải nghiệm vẫn 4 sao.', '["https://images.unsplash.com/photo-1563299796-17596ed6b017?w=400"]', '2025-06-13 10:00:00'),
                                                                                                                                ('2025-06-15 09:00:00', NOW(), 13, 9, 24, 5, 'Nhật Bản mùa lá đỏ Kyoto – đẹp không kém anh đào!', 'Mùa lá đỏ tháng 10 Kyoto đỏ rực tuyệt vời. Fushimi Inari sáng sớm không có người rất linh thiêng. Ramen Kyoto đặc biệt ngon. Shinkansen trải nghiệm rất thú vị. Sẽ đi Nhật lần 3!', '["https://images.unsplash.com/photo-1493976040374-85c8e12f0c0e?w=400","https://images.unsplash.com/photo-1516280440614-37939bbacd81?w=400"]', NULL),
                                                                                                                                ('2025-06-18 16:00:00', NOW(), 3, 7, NULL, 5, 'Ninh Bình đẹp hơn cả Hạ Long!', 'Chèo thuyền Tam Cốc qua 3 hang động – tay chèo tự làm bằng chân rất đặc biệt. Bái Đính to hơn mình nghĩ rất nhiều. Tràng An cảnh đẹp như tranh. Cơm cháy Ninh Bình ngon hơn cả KFC. Rất đáng đi!', NULL, NULL),
                                                                                                                                ('2025-06-20 11:00:00', NOW(), 18, 5, 29, 5, 'Hokkaido tuyết – chuyến đi đời người!', 'Lễ hội tuyết Sapporo điêu khắc tuyết khổng lồ đẹp choáng ngợp. Trượt tuyết Niseko lần đầu mà khá dễ học. Tắm onsen ngoài trời nhìn tuyết rơi – không còn gì tuyệt hơn. Cua hoàng đế Hokkaido ngon số 1!', '["https://images.unsplash.com/photo-1551632811-561732d1e306?w=400"]', '2025-06-21 09:00:00'),
                                                                                                                                ('2025-06-22 14:00:00', NOW(), 15, 8, 30, 5, 'Thái Lan – giá rẻ mà chất lượng cao!', 'Thái Lan là tour có tỷ lệ cost/experience tốt nhất tôi từng đi. Massage Thái rẻ và đỉnh. Đồ ăn Thái ngon tuyệt. Biển Phuket đẹp. Show Alangkarn hoành tráng. Mua đồ Platinum Mall rẻ không thể tin được!', NULL, NULL),
                                                                                                                                ('2025-06-25 10:00:00', NOW(), 19, 7, 40, 4, 'Dubai xa xỉ đúng như tên gọi', 'Burj Khalifa ấn tượng nhất. Safari sa mạc rất vui và thú vị. Nhưng Dubai Mall quá đắt, chỉ dạo chơi chứ không dám mua. Thời tiết tháng 10 mát hơn nhiều so với mùa hè. Sẽ cân nhắc đi lại vào mùa đông.', '["https://images.unsplash.com/photo-1518684079-3c830dcef090?w=400"]', NULL),
                                                                                                                                ('2025-06-27 15:30:00', NOW(), 6, 4, NULL, 5, 'Phú Quốc mùa khô tháng 11 – tuyệt vời!', 'Đây là lần thứ 3 tôi đến Phú Quốc và lần này là đẹp nhất. Mùa khô tháng 11 biển cực kỳ êm, trong và sóng nhỏ. Cáp treo Hòn Thơm mới nhìn xuống biển rùng mình. Hải sản tươi ngon. 5 sao không thể khác!', '["https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=400","https://images.unsplash.com/photo-1596394516093-501ba68a0ba6?w=400"]', '2025-06-28 09:00:00'),
                                                                                                                                ('2025-06-30 11:00:00', NOW(), 14, 10, 38, 5, 'Hàn Quốc mùa anh đào tháng 4 quá đẹp!', 'Công viên Yeouido anh đào nở rộ đúng peak – chụp ảnh đẹp không tưởng. BBQ bò Hanwoo mềm và ngọt hơn bò VN nhiều. Cosmetic Myeongdong mua rất nhiều mà vẫn tiết kiệm hơn VN. Tour 10/10!', NULL, NULL),
                                                                                                                                ('2025-07-02 14:00:00', NOW(), 2, 4, NULL, 4, 'Sapa trekking mệt nhưng xứng đáng!', 'Trekking 15km qua các bản làng khá mệt nhưng cảnh đẹp xứng đáng mọi mệt mỏi. Bản Cát Cát trẻ em H''Mông dễ thương. Homestay ấm cúng dù không đủ tiện nghi. Lần sau sẽ đặt phòng riêng thay homestay.', '["https://images.unsplash.com/photo-1571368618038-cf6afe56e9cf?w=400"]', NULL),
                                                                                                                                ('2025-07-05 09:30:00', NOW(), 5, 6, NULL, 5, 'Huế – cố đô đầy chiều sâu lịch sử', 'Đại Nội Huế to lớn và tráng lệ hơn mình nghĩ. Lăng Minh Mạng kiến trúc cực kỳ tinh tế. Thuyền rồng sông Hương lúc hoàng hôn lãng mạn lắm. Ẩm thực cung đình Huế đặc sắc và tinh tế. Rất đáng đến!', '["https://images.unsplash.com/photo-1598935898639-81586f7d2129?w=400"]', NULL),
                                                                                                                                ('2025-07-08 16:00:00', NOW(), 21, 12, 34, 5, 'Angkor Wat bình minh – trải nghiệm đỉnh cao!', 'Dậy lúc 4h30 sáng để đón bình minh Angkor Wat – xứng đáng ngàn lần! Phản chiếu đền trong hồ nước lúc mặt trời mọc đẹp như tranh thiên đường. Tour Campuchia giá hợp lý mà chất lượng cao. Sẽ giới thiệu bạn bè!', NULL, NULL);


