-- ### 11. contacts (20 records)
-- ============================================================
INSERT INTO public.contacts (created_at, full_name, email, phone, message, admin_reply, replied_at) VALUES
                                                                                                        ('2025-04-01 09:00:00', 'Nguyễn Thị Hoa', 'hoa.nguyen.hcm@gmail.com', '0901111222', 'Tôi muốn hỏi về tour Phú Quốc 4N3Đ, tour có bao gồm vé máy bay không? Giá tour có thể giảm thêm cho nhóm 5 người không?', 'Dạ chào chị Hoa! Tour Phú Quốc 4N3Đ của chúng tôi đã bao gồm vé máy bay khứ hồi. Nhóm từ 5 người trở lên được giảm thêm 5% trên giá tour. Chị có thể liên hệ hotline 1800-1234 để tư vấn chi tiết hơn ạ!', '2025-04-01 15:00:00'),
                                                                                                        ('2025-04-03 14:30:00', 'Trần Văn Minh', 'minh.tran.hn@gmail.com', '0912222333', 'Tôi muốn đặt tour Nhật Bản mùa anh đào tháng 4/2025 cho 2 người. Tour còn chỗ không? Có thể thanh toán trước 50% không?', 'Chào anh Minh! Lịch tháng 4 hiện đã đầy chỗ, nhưng còn lịch tháng 10 mùa lá đỏ rất đẹp ạ. Về thanh toán, anh có thể đặt cọc 30% để giữ chỗ.', '2025-04-04 08:30:00'),
                                                                                                        ('2025-04-05 10:00:00', 'Lê Thị Thu Hương', 'thuhuong.le@gmail.com', '0923333444', 'Tôi có con nhỏ 3 tuổi đi cùng, tour Đà Nẵng Hội An có phù hợp không? Có dịch vụ giữ trẻ không?', NULL, NULL),
                                                                                                        ('2025-04-08 16:45:00', 'Phạm Đức Anh', 'ducanh.pham@yahoo.com', '0934444555', 'Xin hỏi tour Châu Âu 10N9Đ có yêu cầu visa Schengen không? Công ty có hỗ trợ làm visa không và mất bao lâu?', 'Chào anh Đức Anh! Tour Châu Âu yêu cầu visa Schengen. Công ty chúng tôi hỗ trợ làm visa trọn gói, thời gian xử lý 15-20 ngày làm việc. Phí visa khoảng 2.500.000đ/người.', '2025-04-09 09:00:00'),
                                                                                                        ('2025-04-10 11:30:00', 'Nguyễn Thị Lan', 'lan.nguyen.hcm@gmail.com', '0945555666', 'Tour Hàn Quốc tháng 12 Giáng sinh Seoul có tuyết rơi không? Cần chuẩn bị gì về quần áo ấm?', 'Chào chị Lan! Tháng 12 Seoul nhiệt độ khoảng -5 đến 5 độ C, có tuyết rơi rất đẹp. Chị nên chuẩn bị áo phao, khăn len, găng tay, ủng chống trượt tuyết ạ.', '2025-04-10 16:00:00'),
                                                                                                        ('2025-04-12 09:15:00', 'Vũ Hoàng Nam', 'hoangnam.vu@gmail.com', '0956666777', 'Hỏi về tour Bali honeymoon, có package đặc biệt cho cặp đôi không? Có thể thêm dinner lãng mạn bên bãi biển không?', NULL, NULL),
                                                                                                        ('2025-04-15 14:00:00', 'Bùi Thị Minh Châu', 'minhchau.bui@gmail.com', '0967777888', 'Tôi muốn đặt tour Sapa trekking cho nhóm 8 người dịp 2/9. Tour có discount cho nhóm lớn không?', 'Chào chị Minh Châu! Nhóm 8 người được discount 8%, và tặng thêm 1 suất tắm thuốc người Dao trị giá 200.000đ/người. Dịp 2/9 rất đẹp vì lúa bắt đầu chín vàng!', '2025-04-16 08:00:00'),
                                                                                                        ('2025-04-18 10:30:00', 'Đặng Văn Hùng', 'hung.dang.vn@gmail.com', '0978888999', 'Tôi muốn hỏi tour Dubai có cần visa không? Công ty có hỗ trợ làm visa UAE không?', 'Chào anh Hùng! Người Việt Nam cần visa UAE. Chúng tôi hỗ trợ làm visa trọn gói 1.800.000đ/người, thời gian 5-7 ngày làm việc. Tour đã bao gồm phí dịch vụ visa ạ.', '2025-04-18 16:30:00'),
                                                                                                        ('2025-04-20 15:00:00', 'Nguyễn Quốc Trung', 'quoctrung.nguyen@gmail.com', '0989999000', 'Hỏi về tour Côn Đảo tháng 10 xem rùa đẻ trứng. Có đảm bảo thấy rùa không? Cần đặt trước bao lâu?', NULL, NULL),
                                                                                                        ('2025-04-22 11:45:00', 'Lê Thị Khánh Linh', 'khanhlinh.le@gmail.com', '0990001111', 'Tôi 65 tuổi, muốn hỏi tour Miền Tây sông nước có phù hợp với người cao tuổi không? Chương trình có mệt không?', 'Chào chị Khánh Linh! Tour Miền Tây rất phù hợp với người cao tuổi, không cần leo núi hay đi bộ nhiều. Chương trình chủ yếu đi thuyền và tham quan. Chúng tôi sẽ sắp xếp chỗ ngồi thoải mái và ghế tay vịn ạ.', '2025-04-23 09:00:00'),
                                                                                                        ('2025-04-25 14:30:00', 'Trần Anh Tuấn', 'anhtuan.tran@outlook.com', '0901112222', 'Tôi muốn hỏi tour Phú Quốc có gói gia đình không? Có trẻ em 5 và 8 tuổi đi cùng.', NULL, NULL),
                                                                                                        ('2025-04-28 10:00:00', 'Phan Thị Ngọc Bích', 'ngocbich.phan@gmail.com', '0912223333', 'Nhóm công ty 20 người muốn đặt tour team building Mộc Châu 2N1Đ. Có thể customize chương trình không?', 'Chào chị Ngọc Bích! Chúng tôi có chuyên tổ chức team building theo yêu cầu. Nhóm 20 người tại Mộc Châu có thể bổ sung các hoạt động: chèo thuyền kayak, leo núi, cắm trại, BBQ tập thể. Liên hệ trực tiếp để báo giá nhé!', '2025-04-29 08:30:00'),
                                                                                                        ('2025-05-01 09:30:00', 'Hoàng Minh Quân', 'minhquan.hoang@gmail.com', '0923334444', 'Hỏi về bảo hiểm du lịch quốc tế, tour nước ngoài có bao gồm bảo hiểm không? Mức bảo hiểm bao nhiêu?', 'Chào anh Minh Quân! Các tour nước ngoài của chúng tôi đều bao gồm bảo hiểm du lịch quốc tế Bảo Việt, mức bảo hiểm 50.000 USD/người cho tai nạn và 20.000 USD cho y tế. Anh có thể mua thêm bảo hiểm cao hơn nếu cần ạ.', '2025-05-01 15:00:00'),
                                                                                                        ('2025-05-03 16:00:00', 'Lý Thị Phương Thảo', 'phuongthao.ly@gmail.com', '0934445555', 'Xin hỏi tour Úc 9N8Đ mùa xuân tháng 9 có xem hoa anh đào ở Canberra không?', NULL, NULL),
                                                                                                        ('2025-05-05 11:00:00', 'Nguyễn Văn Khôi', 'vankhoinguyen@gmail.com', '0945556666', 'Tour Hạ Long có chọn phòng cabin trên du thuyền được không? Cabin có cửa sổ nhìn ra biển không?', 'Chào anh Khôi! Tàu có nhiều loại cabin: Standard (cửa sổ), Deluxe (cửa kính lớn nhìn biển), Suite (ban công riêng). Anh book sớm sẽ có nhiều lựa chọn hơn. Giá cabin Deluxe chênh thêm 500k/người ạ.', '2025-05-06 09:00:00'),
                                                                                                        ('2025-05-08 14:30:00', 'Đỗ Thị Thanh Hà', 'thanhha.do@gmail.com', '0956667777', 'Tôi đặt tour Nhật Bản cho 4 người nhưng 1 người bị hủy đột xuất. Chính sách hoàn tiền như thế nào?', 'Chào chị Thanh Hà! Chính sách hoàn tiền: trước 30 ngày hoàn 100%, 15-29 ngày hoàn 70%, 8-14 ngày hoàn 50%, 0-7 ngày không hoàn. Trường hợp có giấy chứng nhận bệnh viện được xem xét riêng ạ.', '2025-05-09 08:00:00'),
                                                                                                        ('2025-05-10 10:00:00', 'Phan Đức Tuấn', 'ductuan.phan@gmail.com', '0967778888', 'Xin hỏi tour Mỹ 12N có ghé Hawaii không? Nếu không có thể thêm điểm Hawaii được không?', NULL, NULL),
                                                                                                        ('2025-05-12 15:45:00', 'Bùi Thị Xuân Mai', 'xuanmai.bui@gmail.com', '0978889999', 'Tour Singapore Malaysia, trẻ em 2 tuổi có tính giá không? Có cần passport cho trẻ không?', 'Chào chị Xuân Mai! Trẻ dưới 2 tuổi không tính tiền nhưng không có chỗ ngồi riêng. Mọi trẻ em kể cả dưới 2 tuổi đều cần hộ chiếu khi đi nước ngoài ạ.', '2025-05-13 09:30:00'),
                                                                                                        ('2025-05-15 09:00:00', 'Ngô Thanh Tùng', 'thanhtung.ngo@gmail.com', '0989990000', 'Tour Châu Âu 10N có thể kéo dài thêm 2 ngày tự do ở Paris không? Chi phí phát sinh như thế nào?', NULL, NULL),
                                                                                                        ('2025-05-18 14:00:00', 'Trần Thị Diệu Linh', 'dieulinh.tran@gmail.com', '0901223344', 'Tôi muốn hỏi về tour Quy Nhơn, resort FLC có bao gồm trong tour không? Có thể nâng cấp phòng không?', 'Chào chị Diệu Linh! Tour Quy Nhơn bao gồm khách sạn FLC tiêu chuẩn. Nâng cấp lên phòng Sea View chênh thêm 300k/đêm, phòng Suite 800k/đêm. Chị liên hệ trước để đặt phòng đặc biệt nhé ạ!', '2025-05-19 08:30:00');


